  ('real-estate-moex-01562', 'real-estate', 'real-estate-moex-104-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '依都市計畫法規定，未發布細部計畫地區，應限制其建築使用及變更地形。但主要計畫發布至少已逾 多少年以上，而能確定建築線者，得依有關建築法令之規定，由主管建築機關指定建築線，核發建築 執照？', '["一年", "二年", "三年", "五年"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:09+00:00", "source_pdf_sha1": "6ad9e9774ff9", "answer_pdf_sha1": "5c8489f89016", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "601", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "土地法與土地相關稅法概要", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
