  ('real-estate-moex-01565', 'real-estate', 'real-estate-moex-104-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '公有出租耕地，經依法辦理無償撥用時，其應補償耕地承租人之費用，依平均地權條例規定，應由下列 何者負擔？', '["出租機關", "耕地原管理機關", "需地機關", "耕地原主管機關"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:09+00:00", "source_pdf_sha1": "6ad9e9774ff9", "answer_pdf_sha1": "5c8489f89016", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "601", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "土地法與土地相關稅法概要", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01566', 'real-estate', 'real-estate-moex-104-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '依耕地三七五減租條例規定，有關租佃爭議處理之敘述，下列何者錯誤？', '["耕地租佃爭議，先後由鄉（鎮、市、區）公所耕地租佃委員會調處及直轄市或縣（市）政府耕地租佃 委員會調解", "非經調解、調處，不得起訴", "租佃爭議之訴訟，免收裁判費", "調解、調處成立者，當事人一方不履行其義務時，他造當事人得逕向該管司法機關聲請強制執行"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:09+00:00", "source_pdf_sha1": "6ad9e9774ff9", "answer_pdf_sha1": "5c8489f89016", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "601", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "土地法與土地相關稅法概要", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01567', 'real-estate', 'real-estate-moex-104-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '工業用地之土地所有權人申請按千分之十計徵地價稅，應於何時提出申請，逾期申請者，自申請之次年 期開始適用？', '["每年八月三十一日", "每年九月三十日", "每年（期）地價稅開徵四十日前", "每年（期）地價稅開徵六十日前"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:09+00:00", "source_pdf_sha1": "6ad9e9774ff9", "answer_pdf_sha1": "5c8489f89016", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "601", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "土地法與土地相關稅法概要", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01568', 'real-estate', 'real-estate-moex-104-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '依都市計畫法指定之公共設施保留地，尚未被徵收前之移轉，其土地增值稅之課徵，下列何者正確？', '["減徵百分之四十", "準用被徵收之土地予以免徵之", "減半徵收之", "以該土地之原地價計算漲價總數額課徵之"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:09+00:00", "source_pdf_sha1": "6ad9e9774ff9", "answer_pdf_sha1": "5c8489f89016", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "601", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "土地法與土地相關稅法概要", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01569', 'real-estate', 'real-estate-moex-104-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '依土地稅法規定，作農業使用之農業用地，移轉與自然人時，下列有關土地增值稅之課徵，何者正確？', '["不課徵土地增值稅", "得申請不課徵土地增值稅", "免徵土地增值稅", "得申請免徵土地增值稅"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:09+00:00", "source_pdf_sha1": "6ad9e9774ff9", "answer_pdf_sha1": "5c8489f89016", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "601", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "土地法與土地相關稅法概要", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01570', 'real-estate', 'real-estate-moex-104-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '關於區段徵收土地，於領回抵價地後第一次移轉時，用以計算漲價總數額之原地價，有其規定之標準， 下列何者正確？', '["以區段徵收區之開發成本為原地價", "以原土地所有權人移轉時之申報現值為原地價", "以政府核定之原規定地價為原地價", "以原土地所有權人實際領回抵價地之地價為原地價"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:09+00:00", "source_pdf_sha1": "6ad9e9774ff9", "answer_pdf_sha1": "5c8489f89016", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "601", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "土地法與土地相關稅法概要", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01571', 'real-estate', 'real-estate-moex-104-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '土地所有權移轉或設定典權時，倘雙方當事人共同申報之移轉現值，經審核超過當期公告土地現值者， 應以下列何者為準，依規定徵收土地增值稅？', '["按當期公告土地現值", "按前次移轉現值", "按雙方當事人自行申報之移轉現值", "按稅捐機關查證之移轉現值"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:09+00:00", "source_pdf_sha1": "6ad9e9774ff9", "answer_pdf_sha1": "5c8489f89016", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "601", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "土地法與土地相關稅法概要", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL)
